      totalInvestors: investorsRes.count || 0,
      totalDeals: dealsRes.count || 0,
      deploymentMarker: DEPLOYMENT_MARKER,
    });
  } catch (err: any) { return json({ error: err.message, deploymentMarker: DEPLOYMENT_MARKER }, 500); }
}

